<?php

declare(strict_types=1);

/**
 * Command Extension Registry.
 *
 * Manages command extensions at runtime. Loads the compiled extension map
 * generated by `CommandExtensionCompiler` during `di:compile`.
 *
 * Commands access their extensions via `$this->extensions()` in BaseCommand,
 * which delegates to this registry.
 *
 * @category Console
 *
 * @since    1.0.0
 */

namespace Stackra\Console\Registry;

use Illuminate\Container\Attributes\Singleton;
use Illuminate\Contracts\Container\Container;

/**
 * Registry for command extensions.
 *
 * ## How It Works:
 * 1. `CommandExtensionCompiler` scans for `#[AsCommand(extends: '...')]` attributes
 * 2. Generates `bootstrap/cache/command-extensions.php` with the extension map
 * 3. This registry loads that map and provides it to commands via `getExtensionsFor()`
 * 4. Parent commands call `$this->extensions()` which delegates here
 *
 * ## Example Extension Map:
 * ```php
 * [
 *     'app:clear' => [
 *         ['class' => ClearCompiledCommand::class, 'name' => 'di:clear', 'priority' => 60, 'description' => 'DI artifacts'],
 *     ],
 *     'app:optimize' => [
 *         ['class' => CompileCommand::class, 'name' => 'di:compile', 'priority' => 60, 'description' => 'DI compilation'],
 *     ],
 * ]
 * ```
 */
#[Singleton]
class CommandExtensionRegistry
{
    /**
     * Cached extension map.
     *
     * @var array<string, array<array{class: string, name: string, priority: int, description: string}>>|null
     */
    protected ?array $extensions = null;

    /**
     * Create a new registry instance.
     */
    public function __construct(
        protected Container $container,
    ) {}

    /**
     * Load the extension map from cache.
     *
     * @return array<string, array<array{class: string, name: string, priority: int, description: string}>>
     */
    public function load(): array
    {
        if ($this->extensions !== null) {
            return $this->extensions;
        }

        $cachePath = $this->container->bootstrapPath('cache/command-extensions.php');

        $this->extensions = file_exists($cachePath) ? require $cachePath : [];

        return $this->extensions;
    }

    /**
     * Get extensions for a specific parent command.
     *
     * @param  string  $parentCommand  The parent command name (e.g., 'app:clear').
     * @return array<array{class: string, name: string, priority: int, description: string}>
     */
    public function getExtensionsFor(string $parentCommand): array
    {
        $extensions = $this->load();

        return $extensions[$parentCommand] ?? [];
    }

    /**
     * Check if a parent command has extensions.
     */
    public function hasExtensions(string $parentCommand): bool
    {
        return $this->getExtensionsFor($parentCommand) !== [];
    }

    /**
     * Get all registered extensions.
     *
     * @return array<string, array<array{class: string, name: string, priority: int, description: string}>>
     */
    public function all(): array
    {
        return $this->load();
    }

    /**
     * Clear the cached extensions.
     */
    public function clear(): bool
    {
        $cachePath = $this->container->bootstrapPath('cache/command-extensions.php');

        if (file_exists($cachePath)) {
            unlink($cachePath);
            $this->extensions = null;

            return true;
        }

        return false;
    }

    /**
     * Get the cache file path.
     */
    public function getCachePath(): string
    {
        return $this->container->bootstrapPath('cache/command-extensions.php');
    }
}
